package org.apache.commons.csv;
import static org.apache.commons.csv.Constants.BACKSLASH;
import static org.apache.commons.csv.Constants.COMMA;
import static org.apache.commons.csv.Constants.COMMENT;
import static org.apache.commons.csv.Constants.EMPTY;
import static org.apache.commons.csv.Constants.CR;
import static org.apache.commons.csv.Constants.CRLF;
import static org.apache.commons.csv.Constants.DOUBLE_QUOTE_CHAR;
import static org.apache.commons.csv.Constants.LF;
import static org.apache.commons.csv.Constants.PIPE;
import static org.apache.commons.csv.Constants.SP;
import static org.apache.commons.csv.Constants.TAB;
import java.io.File;
import java.io.FileOutputStream;
import java.io.IOException;
import java.io.OutputStreamWriter;
import java.io.Reader;
import java.io.Serializable;
import java.io.StringWriter;
import java.nio.charset.Charset;
import java.nio.file.Files;
import java.nio.file.Path;
import java.sql.ResultSet;
import java.sql.ResultSetMetaData;
import java.sql.SQLException;
import java.util.Arrays;
import java.util.HashSet;
import java.util.Set;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;
import java.lang.reflect.Modifier;

class CSVFormatTest {

    @Test
    void testGetEscapeCharacter_DefaultInstance() throws Exception {
        // DEFAULT instance has escapeCharacter = null
        setFinalStaticField(CSVFormat.class, "DEFAULT", CSVFormat.DEFAULT);
        assertNull(CSVFormat.DEFAULT.getEscapeCharacter());
    }

    @Test
    void testGetEscapeCharacter_InformixUnload() throws Exception {
        // INFORMIX_UNLOAD instance has escapeCharacter = BACKSLASH
        setFinalStaticField(CSVFormat.class, "INFORMIX_UNLOAD", CSVFormat.INFORMIX_UNLOAD);
        Character escape = CSVFormat.INFORMIX_UNLOAD.getEscapeCharacter();
        assertNotNull(escape);
        assertEquals('\\', escape.charValue());
    }

    @Test
    void testGetEscapeCharacter_MySQL() throws Exception {
        // MYSQL instance has escapeCharacter = BACKSLASH
        setFinalStaticField(CSVFormat.class, "MYSQL", CSVFormat.MYSQL);
        Character escape = CSVFormat.MYSQL.getEscapeCharacter();
        assertNotNull(escape);
        assertEquals('\\', escape.charValue());
    }

    @Test
    void testGetEscapeCharacter_PostgreSQLCSV() throws Exception {
        // POSTGRESQL_CSV instance has escapeCharacter = DOUBLE_QUOTE_CHAR
        setFinalStaticField(CSVFormat.class, "POSTGRESQL_CSV", CSVFormat.POSTGRESQL_CSV);
        Character escape = CSVFormat.POSTGRESQL_CSV.getEscapeCharacter();
        assertNotNull(escape);
        assertEquals('"', escape.charValue());
    }

    @Test
    void testGetEscapeCharacter_PostgreSQLText() throws Exception {
        // POSTGRESQL_TEXT instance has escapeCharacter = DOUBLE_QUOTE_CHAR
        setFinalStaticField(CSVFormat.class, "POSTGRESQL_TEXT", CSVFormat.POSTGRESQL_TEXT);
        Character escape = CSVFormat.POSTGRESQL_TEXT.getEscapeCharacter();
        assertNotNull(escape);
        assertEquals('"', escape.charValue());
    }

    @Test
    void testGetEscapeCharacter_RFC4180() throws Exception {
        // RFC4180 inherits from DEFAULT, escapeCharacter == null
        setFinalStaticField(CSVFormat.class, "RFC4180", CSVFormat.RFC4180);
        assertNull(CSVFormat.RFC4180.getEscapeCharacter());
    }

    @Test
    void testGetEscapeCharacter_TDF() throws Exception {
        // TDF inherits from DEFAULT, escapeCharacter == null
        setFinalStaticField(CSVFormat.class, "TDF", CSVFormat.TDF);
        assertNull(CSVFormat.TDF.getEscapeCharacter());
    }

    private static void setFinalStaticField(Class<?> clazz, String fieldName, Object newValue) throws Exception {
        Field field = clazz.getDeclaredField(fieldName);
        field.setAccessible(true);

        // Remove final modifier from field
        Field modifiersField = Field.class.getDeclaredField("modifiers");
        modifiersField.setAccessible(true);
        modifiersField.setInt(field, field.getModifiers() & ~Modifier.FINAL);

        field.set(null, newValue);
    }
}
